            badge: "Best Value"
        },
        {
            id: 3,
            title: "Cybersecurity Fundamentals",
            category: "cybersecurity",
            level: "Beginner",
            duration: "10 weeks",
            price: "¥30,000",
            originalPrice: "¥38,000",
            rating: 4.7,
            students: 750,
